function updateClocks(){const n=document.getElementById("local-time"),s=document.getElementById("utc-time"),e=document.getElementById("user-location"),t=new Date,o=t.toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"});n&&(n.textContent=o);const i=t.getUTCHours().toString().padStart(2,"0")+":"+t.getUTCMinutes().toString().padStart(2,"0")+" UTC";s&&(s.textContent=i);try{const t=Intl.DateTimeFormat().resolvedOptions().timeZone,n=t.split("/")[1]?.replace("_"," ")||t;e&&(e.textContent=n)}catch{e&&(e.textContent="Global")}}updateClocks(),setInterval(updateClocks,1e4);const intentions=["Peace begins with a single deep breath.","Healing for the oceans and all within.","Breathe for the world, not just for yourself.","Unity in silence, strength in presence.","Let go of the noise, find the harmony."];function rotateIntention(){const e=document.getElementById("intention-of-moment");if(!e)return;e.style.opacity=0,setTimeout(()=>{e.textContent=`"${intentions[Math.floor(Math.random()*intentions.length)]}"`,e.style.opacity=1},1e3)}setInterval(rotateIntention,8e3)